def solve(grid):
    rows = len(grid)
    cols = len(grid[0])
    out = [row[:] for row in grid]
    for r in range(rows):
        for c in range(9):
            out[r][c] = 0
    staircase_heights = []
    for sc in [1, 3, 5, 7]:
        h = 0
        for r in range(5, 0, -1):
            if grid[r][sc] == 5:
                h += 1
            else:
                break
        staircase_heights.append(h)
    top_border = -1
    bottom_border = -1
    for r in range(rows):
        if all(grid[r][c] == 5 for c in range(9, cols)):
            if top_border == -1:
                top_border = r
            else:
                bottom_border = r
    inner_top = top_border + 1
    inner_bottom = bottom_border - 1
    inner_height = inner_bottom - inner_top + 1
    for idx, (rc, sh) in enumerate(zip([11, 13, 15, 17], staircase_heights)):
        in_vals = [grid[r][rc] for r in range(inner_top, inner_bottom + 1)]
        input_top_5s = 0
        for v in in_vals:
            if v == 5:
                input_top_5s += 1
            else:
                break
        color = 0
        for v in in_vals:
            if v not in [0, 5]:
                color = v
                break
        output_top_5s = max(0, input_top_5s - 1)
        color_count = inner_height - output_top_5s - sh - 1
        new_col = []
        new_col.extend([5] * output_top_5s)
        new_col.extend([color] * color_count)
        new_col.extend([5] * sh)
        new_col.append(0)
        new_col = new_col[:inner_height]
        for j, r in enumerate(range(inner_top, inner_bottom + 1)):
            out[r][rc] = new_col[j]
    for sc, rc in zip([2, 4, 6], [12, 14, 16]):
        for r in range(inner_top, inner_bottom + 1):
            if grid[r][sc] == 5:
                out[r][rc] = 5
    return out
